// SPDX-License-Identifier: MIT

pragma solidity ^0.8.20;

import '../Intents.sol';
import '../safeguards/Safeguards.sol';

/**
 * @title Settler interface
 */
interface ISettler {
    /**
     * @dev The requested operation type is unknown
     */
    error SettlerUnknownOperationType(uint8 opType);

    /**
     * @dev The simulation has been successful
     */
    error SettlerSimulationSuccess(uint256 gasUsed);

    /**
     * @dev The solver is not allowed
     */
    error SettlerSolverNotAllowed(address solver);

    /**
     * @dev The executor is not allowed
     */
    error SettlerExecutorNotAllowed(address executor);

    /**
     * @dev The proposal signer is not allowed
     */
    error SettlerProposalSignerNotAllowed(address signer);

    /**
     * @dev The validator is not allowed
     */
    error SettlerValidatorNotAllowed(address validator);

    /**
     * @dev The validator is duplicated
     */
    error SettlerValidatorDuplicatedOrUnsorted(address previous, address current);

    /**
     * @dev The settler is not the current contract
     */
    error SettlerInvalidSettler(address settler);

    /**
     * @dev The nonce is zero
     */
    error SettlerNonceZero();

    /**
     * @dev The intent has already been executed
     */
    error SettlerIntentAlreadyExecuted(bytes32 hash);

    /**
     * @dev The intent deadline is in the past
     */
    error SettlerIntentPastDeadline(uint256 deadline, uint256 timestamp);

    /**
     * @dev The current chain is not valid
     */
    error SettlerInvalidChain(uint256 chainId);

    /**
     * @dev The recipient is the settler contract
     */
    error SettlerInvalidRecipient(address to);

    /**
     * @dev The user is not a smart account
     */
    error SettlerUserNotSmartAccount(address user);

    /**
     * @dev The amount out is lower than the proposed amount
     */
    error SettlerAmountOutLtProposed(uint256 index, uint256 amountOut, uint256 proposed);

    /**
     * @dev The proposed amount is lower than the minimum amount
     */
    error SettlerProposedAmountLtMinAmount(uint256 index, uint256 proposed, uint256 minAmount);

    /**
     * @dev The proposed amounts array and the tokens out array are not of equal length
     */
    error SettlerInvalidProposedAmounts();

    /**
     * @dev The balance after the proposal execution is lower than the balance before
     */
    error SettlerPostBalanceOutLtPre(uint256 index, uint256 post, uint256 pre);

    /**
     * @dev The solver fees length does not match the requested by the user
     */
    error SettlerSolverFeeInvalidLength();

    /**
     * @dev The intent operations array is empty
     */
    error SettlerIntentOperationsEmpty();

    /**
     * @dev The proposal datas length does not match the intent operations length
     */
    error SettlerProposalDataInvalidLength();

    /**
     * @dev The solver fee is too high
     */
    error SettlerSolverFeeTooHigh(uint256 fee, uint256 max);

    /**
     * @dev The intent validations are not enough
     */
    error SettlerIntentValidationsNotEnough(uint256 min, uint256 current);

    /**
     * @dev The proposal deadline is in the past
     */
    error SettlerProposalPastDeadline(uint256 deadline, uint256 timestamp);

    /**
     * @dev The proposal data is not empty
     */
    error SettlerProposalDataNotEmpty();

    /**
     * @dev The rescue funds recipient is zero
     */
    error SettlerRescueFundsRecipientZero();

    /**
     * @dev The list of safeguards exceed the maximum allowed
     */
    error SettlerTooManySafeguards(uint256 lengthRequested);

    /**
     * @dev The chains of a swap operation do not match the swap type (single or cross chain)
     */
    error SettlerOperationChainsMismatch();

    /**
     * @dev A CrossChainSwap operation must be the only operation in the intent
     */
    error SettlerCrossChainSwapMustBeOnlyOperation();

    /**
     * @dev The new smart accounts handler is zero
     */
    error SmartAccountsHandlerZero();

    /**
     * @dev The new dynamic call encoder is zero
     */
    error SettlerDynamicCallEncoderZero();

    /**
     * @dev Custom events emitted for each operation
     */
    event OperationExecuted(
        address indexed user,
        bytes32 indexed topic,
        uint8 indexed opType,
        Operation operation,
        Proposal proposal,
        bytes32 intentHash,
        uint256 index,
        bytes output,
        bytes data
    );

    /**
     * @dev Emitted every time an intent is fulfilled
     */
    event ProposalExecuted(bytes32 indexed proposal);

    /**
     * @dev Emitted every time tokens are withdrawn from the contract balance
     */
    event FundsRescued(address indexed token, address indexed recipient, uint256 amount);

    /**
     * @dev Emitted every time the smart accounts handler is set
     */
    event SmartAccountsHandlerSet(address indexed smartAccountsHandler);

    /**
     * @dev Emitted every time the operations validator is set
     */
    event OperationsValidatorSet(address indexed operationsValidator);

    /**
     * @dev Emitted every time the dynamic call encoder is set
     */
    event DynamicCallEncoderSet(address indexed dynamicCallEncoder);

    /**
     * @dev Emitted every time a safeguard is set
     */
    event SafeguardSet(address indexed user);

    /**
     * @dev Tells the reference to the Mimic controller
     */
    function controller() external view returns (address);

    /**
     * @dev Tells the reference to the smart accounts handler
     */
    function smartAccountsHandler() external view returns (address);

    /**
     * @dev Tells the reference to the operations validator
     */
    function operationsValidator() external view returns (address);

    /**
     * @dev Tells the reference to the dynamic call encoder
     */
    function dynamicCallEncoder() external view returns (address);

    /**
     * @dev Tells the block at which an intent was executed. Returns 0 if unexecuted.
     * @param hash Hash of the intent being queried
     */
    function getIntentBlock(bytes32 hash) external view returns (uint256);

    /**
     * @dev Tells the safeguard set for a user
     * @param user Address of the user being queried
     */
    function getUserSafeguard(address user) external view returns (bytes memory);

    /**
     * @dev Tells the hash of an intent
     * @param intent Intent to get the hash of
     */
    function getIntentHash(Intent memory intent) external pure returns (bytes32);

    /**
     * @dev Tells the hash of a proposal
     * @param proposal Proposal to be hashed
     * @param intent Intent being fulfilled by the requested proposal
     * @param solver Address of the solver that made the proposal
     */
    function getProposalHash(Proposal memory proposal, Intent memory intent, address solver)
        external
        pure
        returns (bytes32);

    /**
     * @dev Withdraws ERC20 or native tokens from the contract
     * @param token Address of the token to be withdrawn
     * @param recipient Address of the account receiving the tokens
     * @param amount Amount of tokens to be withdrawn
     */
    function rescueFunds(address token, address recipient, uint256 amount) external;

    /**
     * @dev Sets a new smart accounts handler
     * @param newSmartAccountsHandler New smart accounts handler to be set
     */
    function setSmartAccountsHandler(address newSmartAccountsHandler) external;

    /**
     * @dev Sets a new operations validator address
     * @param newOperationsValidator New operations validator to be set
     */
    function setOperationsValidator(address newOperationsValidator) external;

    /**
     * @dev Sets a new dynamic call encoder address
     * @param newDynamicCallEncoder New dynamic call encoder to be set
     */
    function setDynamicCallEncoder(address newDynamicCallEncoder) external;

    /**
     * @dev Sets a safeguard for a user
     * @param safeguard Safeguard to be set
     */
    function setSafeguard(bytes memory safeguard) external;

    /**
     * @dev Executes a proposal to fulfill an intent
     * @param intent Intent to be fulfilled
     * @param proposal Proposal to be executed
     * @param signature Proposal signature
     */
    function execute(Intent memory intent, Proposal memory proposal, bytes memory signature) external;

    /**
     * @dev Simulates an execution. It will always revert. Successful executions are returned as
     * `SettlerSimulationSuccess` errors. Any other error should be treated as failure.
     * @param intent Intent to be fulfilled
     * @param proposal Proposal to be executed
     * @param signature Proposal signature
     */
    function simulate(Intent memory intent, Proposal memory proposal, bytes memory signature) external;
}

